import matplotlib.pyplot as plt
def task_func(df: pd.DataFrame, tuples: list, n_plots: int) -> (pd.DataFrame, list):

    if not isinstance(df, pd.DataFrame):
        raise TypeError("Input 'df' must be a pandas DataFrame.")
    if not isinstance(tuples, list):
        raise TypeError("Input 'tuples' must be a list.")
    if not isinstance(n_plots, int) or n_plots < 0:
        raise ValueError("Input 'n_plots' must be a non-negative integer.")

    for col, val in tuples:
        if col not in df.columns:
            raise ValueError(f"Column '{col}' not found in DataFrame.")
        df = df[df[col] != val]

    plots = []
    if not df.empty:
        if len(df.columns) < 2:
            return df, plots

        num_cols = len(df.columns)

        if n_plots > (num_cols * (num_cols - 1)) // 2:
            n_plots = (num_cols * (num_cols - 1)) // 2


        all_pairs = []
        for i in range(num_cols):
            for j in range(i + 1, num_cols):
                all_pairs.append((df.columns[i], df.columns[j]))

        if n_plots > len(all_pairs):
            n_plots = len(all_pairs)

        selected_pairs = sample(all_pairs, n_plots)

        for col1, col2 in selected_pairs:
            g = sns.jointplot(x=col1, y=col2, data=df)
            plots.append(g)

    return df, plots

