import pandas as pd
from scipy.stats import pearsonr
import numpy as np
def task_func(data):
    if len(data) < 2:
        return np.nan

    try:
        data['score'] = data['score'].astype(float)
    except ValueError:
        return np.nan                                       

    grades = data['grade'].unique()
    grades_sorted = sorted(grades)
    grade_mapping = {grade: i for i, grade in enumerate(grades_sorted)}
    data['encoded_grade'] = data['grade'].map(grade_mapping)

    scores = data['score']
    encoded_grades = data['encoded_grade']

    try:
        correlation, _ = pearsonr(scores, encoded_grades)
        return correlation
    except ValueError:
        return np.nan

import re
import nltk
from string import punctuation
def task_func(df):
    if "Title" not in df.columns or "Content" not in df.columns:
        raise ValueError("DataFrame must include 'Title' and 'Content' columns.")
    pattern = re.compile(r'(like|what)', re.IGNORECASE)
    interesting_articles = df[df['Title'].apply(lambda x: bool(pattern.search(x)))]

    word_freq = {}
    if interesting_articles.empty:
        return word_freq

    for content in interesting_articles['Content']:
        tokens = nltk.word_tokenize(content)
        for token in tokens:
            if token not in punctuation:
                if token not in word_freq:
                    word_freq[token] = 1
                else:
                    word_freq[token] += 1

    return word_freq

import numpy as np
import json
def task_func(data_list, json_file_name="mean_values.json"):
    if not all(isinstance(sublist, list) for sublist in data_list):
        raise ValueError("Input data_list must be a list of lists.")

    transposed_data = list(zip(*data_list))

    mean_values = {}
    for i, values in enumerate(transposed_data):
        numeric_values = [v for v in values if isinstance(v, (int, float))]
        if numeric_values:
            mean_values[f"Position {i}"] = np.mean(numeric_values)
        else:
            mean_values[f"Position {i}"] = None                                      

    with open(json_file_name, "w") as json_file:
        json.dump(mean_values, json_file, indent=4)

    return mean_values

